/* === assets/js/config.js === */
/**
 * NGSSAI API - Configuration
 * =====================================
 * Merkezi API ve WebSocket URL konfigürasyonu.
 * Tüm modüller bu dosyadaki değerleri kullanmalıdır.
 *
 * v2.48.0: Production-ready dynamic URL detection.
 * - localhost → development (port 8002)
 * - Diğer hostname → production (aynı origin, Nginx reverse proxy)
 */

// --- Dynamic API Base URL ---
// Development: Frontend serve.py (port 5500) → Backend farklı port (8002)
// Production:  Nginx reverse proxy (port 80/443) → aynı origin
const _isDevServer = window.location.port === '5500';

const API_BASE_URL = _isDevServer
    ? 'http://localhost:8002'
    : window.location.origin;  // Nginx: aynı origin (port 80/443)

// WebSocket URL (ws → wss otomatik HTTPS desteği)
const WS_BASE_URL = _isDevServer
    ? 'ws://localhost:8002/api/ws'
    : `${window.location.protocol === 'https:' ? 'wss' : 'ws'}://${window.location.host}/api/ws`;

// Global erişim: Diğer modüller window.API_BASE_URL ile erişir
window.API_BASE_URL = API_BASE_URL;
window.WS_BASE_URL = WS_BASE_URL;

const API_ENDPOINTS = {
    auth: {
        login: '/api/auth/login',
        register: '/api/auth/register',
        refresh: '/api/auth/refresh'
    },
    users: {
        list: '/api/users/list',
        approve: '/api/users/approve',
        me: '/api/users/me'
    },
    organizations: {
        list: '/api/organizations',
        create: '/api/organizations',
        detail: (id) => `/api/organizations/${id}`,
        update: (id) => `/api/organizations/${id}`,
        delete: (id) => `/api/organizations/${id}`
    },
    rag: {
        files: '/api/rag/files',
        upload: '/api/rag/upload-files',
        search: '/api/rag/search'
    }
};


/* === assets/js/toast.js === */
/**
 * NGSSAI API - Toast Notifications
 */

function showToast(message, type = 'info') {
    const container = document.getElementById('toast-container') || createToastContainer();

    const toast = document.createElement('div');
    toast.className = `toast toast-${type}`;
    toast.innerHTML = `
        <div class="toast-content">
            <i class="fas fa-${getToastIcon(type)}"></i>
            <span>${message}</span>
        </div>
    `;

    container.appendChild(toast);

    setTimeout(() => toast.classList.add('show'), 10);

    setTimeout(() => {
        toast.classList.remove('show');
        setTimeout(() => toast.remove(), 300);
    }, 3000);
}

function createToastContainer() {
    let container = document.getElementById('toast-container');
    if (!container) {
        container = document.createElement('div');
        container.id = 'toast-container';
        container.style.cssText = 'position:fixed;top:20px;right:20px;z-index:100002;';
        document.body.appendChild(container);
    }
    return container;
}

function getToastIcon(type) {
    const icons = {
        success: 'check-circle',
        error: 'exclamation-circle',
        warning: 'exclamation-triangle',
        info: 'info-circle'
    };
    return icons[type] || icons.info;
}

// Expose globally
window.showToast = showToast;


/* === assets/js/modal.js === */
/**
 * NGSSAI Global Modal System
 * Modern SaaS Modal Dialogs
 * 
 * Usage:
 * VyraModal.confirm({ title: 'Silme', message: 'Emin misiniz?', onConfirm: () => {} });
 * VyraModal.alert({ type: 'success', title: 'Başarılı', message: 'İşlem tamamlandı' });
 * VyraModal.danger({ title: 'Dikkat', message: 'Bu işlem geri alınamaz', onConfirm: () => {} });
 */

const VyraModal = {
    overlay: null,
    modal: null,
    isOpen: false,

    /**
     * Modal sistemi başlat
     */
    init() {
        if (this.overlay) return;

        // Overlay oluştur
        this.overlay = document.createElement('div');
        this.overlay.className = 'vyra-modal-overlay';
        this.overlay.innerHTML = `
            <div class="vyra-modal">
                <div class="vyra-modal-header">
                    <div class="vyra-modal-icon warning">
                        <i class="fas fa-exclamation-triangle"></i>
                    </div>
                    <h3 class="vyra-modal-title">Başlık</h3>
                </div>
                <div class="vyra-modal-body">
                    <p class="vyra-modal-message">Mesaj içeriği</p>
                </div>
                <div class="vyra-modal-footer">
                    <button class="vyra-modal-btn cancel" id="vyraModalCancel">İptal</button>
                    <button class="vyra-modal-btn confirm" id="vyraModalConfirm">Onayla</button>
                </div>
            </div>
        `;

        document.body.appendChild(this.overlay);
        this.modal = this.overlay.querySelector('.vyra-modal');

        // Event listeners
        this.overlay.addEventListener('click', (e) => {
            if (e.target === this.overlay) {
                // Overlay'e tıklamada kapatma (opsiyonel)
            }
        });

        // ESC tuşu ile kapatma
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && this.isOpen) {
                this.close();
            }
        });
    },

    /**
     * Icon sınıflarını güncelle
     */
    getIconClass(type) {
        const icons = {
            warning: 'fas fa-exclamation-triangle',
            danger: 'fas fa-trash-alt',
            success: 'fas fa-check-circle',
            info: 'fas fa-info-circle',
            question: 'fas fa-question-circle',
            error: 'fas fa-times-circle',
            network: 'fas fa-wifi'
        };
        return icons[type] || icons.warning;
    },

    /**
     * Modal aç
     */
    open(options) {
        this.init();

        const {
            type = 'warning',
            title = 'Uyarı',
            message = '',
            htmlMessage = null,
            confirmText = 'Onayla',
            cancelText = 'İptal',
            confirmClass = 'confirm',
            showCancel = true,
            onConfirm = null,
            onCancel = null
        } = options;

        // Icon
        const iconEl = this.overlay.querySelector('.vyra-modal-icon');
        iconEl.className = `vyra-modal-icon ${type}`;
        iconEl.innerHTML = `<i class="${this.getIconClass(type)}"></i>`;

        // Title & Message
        this.overlay.querySelector('.vyra-modal-title').textContent = title;
        const msgEl = this.overlay.querySelector('.vyra-modal-message');
        if (htmlMessage) {
            msgEl.innerHTML = htmlMessage;
        } else if (/<[a-z][\s\S]*>/i.test(message)) {
            msgEl.innerHTML = message;
        } else {
            msgEl.textContent = message;
        }

        // Buttons
        const cancelBtn = this.overlay.querySelector('#vyraModalCancel');
        const confirmBtn = this.overlay.querySelector('#vyraModalConfirm');

        cancelBtn.textContent = cancelText;
        cancelBtn.style.display = showCancel ? 'block' : 'none';

        confirmBtn.textContent = confirmText;
        confirmBtn.className = `vyra-modal-btn ${confirmClass}`;

        // Event handlers
        const newCancelBtn = cancelBtn.cloneNode(true);
        cancelBtn.parentNode.replaceChild(newCancelBtn, cancelBtn);
        newCancelBtn.addEventListener('click', () => {
            if (onCancel) onCancel();
            this.close();
        });

        const newConfirmBtn = confirmBtn.cloneNode(true);
        confirmBtn.parentNode.replaceChild(newConfirmBtn, confirmBtn);
        newConfirmBtn.addEventListener('click', () => {
            if (onConfirm) onConfirm();
            this.close();
        });

        // Show
        this.isOpen = true;
        this.overlay.classList.add('active');
        newConfirmBtn.focus();
    },

    /**
     * Modal kapat
     */
    close() {
        if (!this.overlay) return;

        this.isOpen = false;
        this.overlay.classList.remove('active');
    },

    /**
     * Onay diyaloğu (Soru)
     */
    confirm(options) {
        this.open({
            type: 'question',
            confirmClass: 'confirm',
            ...options
        });
    },

    /**
     * Tehlikeli işlem onayı
     */
    danger(options) {
        this.open({
            type: 'danger',
            confirmClass: 'danger',
            confirmText: 'Sil',
            ...options
        });
    },

    /**
     * Uyarı diyaloğu
     */
    warning(options) {
        this.open({
            type: 'warning',
            confirmClass: 'warning',
            confirmText: 'Tamam',
            showCancel: false,
            ...options
        });
    },

    /**
     * Başarı diyaloğu
     */
    success(options) {
        this.open({
            type: 'success',
            confirmClass: 'confirm',
            confirmText: 'Tamam',
            showCancel: false,
            ...options
        });
    },

    /**
     * Bilgi diyaloğu
     */
    info(options) {
        this.open({
            type: 'info',
            confirmClass: 'confirm',
            confirmText: 'Tamam',
            showCancel: false,
            ...options
        });
    },

    /**
     * Hata diyaloğu
     */
    error(options) {
        this.open({
            type: 'error',
            confirmClass: 'danger',
            confirmText: 'Tamam',
            showCancel: false,
            ...options
        });
    },

    /**
     * VPN/Network bağlantı hatası diyaloğu
     * Teknik detayları gizleyerek kullanıcı dostu mesaj gösterir
     */
    vpnError(options = {}) {
        this.open({
            type: 'network',
            title: options.title || 'Bağlantı Hatası',
            message: options.message || 'Corpix desteği için, şirket VPN ya da Wi-Fi açık olmalıdır. Lütfen bağlantı sağlayarak tekrar deneyin.',
            confirmClass: 'warning',
            confirmText: 'Tamam',
            showCancel: false,
            ...options
        });
    }
};

// Auto-init
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => VyraModal.init());
} else {
    VyraModal.init();
}

// Global export
window.VyraModal = VyraModal;


/* === assets/js/notification.js === */
/**
 * NGSSAI Notification Center
 * Modern SaaS Notification System
 * 
 * Usage:
 * NgssNotification.success('Başlık', 'Mesaj');
 * NgssNotification.error('Hata', 'Bir şeyler yanlış gitti');
 * NgssNotification.warning('Uyarı', 'Dikkat edilmeli');
 * NgssNotification.info('Bilgi', 'Bilgilendirme');
 */

const NgssNotification = {
    container: null,
    dropdown: null,
    badge: null,
    list: null,
    notifications: [],
    isOpen: false,
    maxItems: 50,

    /**
     * Notification sistemini başlat
     */
    init() {
        if (this.container) return;
        this.loadFromStorage();
        this.render();
        this.bindEvents();
    },

    /**
     * LocalStorage'dan yükle
     */
    loadFromStorage() {
        try {
            const stored = localStorage.getItem('vyra_notifications');
            if (stored) {
                this.notifications = JSON.parse(stored);
            }
        } catch (e) {
            this.notifications = [];
        }
    },

    /**
     * LocalStorage'a kaydet
     */
    saveToStorage() {
        try {
            localStorage.setItem('vyra_notifications', JSON.stringify(this.notifications));
        } catch (e) {
            console.error('[Notification] Storage error:', e);
        }
    },

    /**
     * HTML render
     */
    render() {
        // Container oluştur
        this.container = document.createElement('div');
        this.container.className = 'notification-center';
        this.container.style.cssText = 'position: relative; display: inline-block;';
        this.container.innerHTML = `
            <div class="notification-bell" id="notificationBell" title="Bildirimler">
                <i class="fas fa-bell"></i>
                <span class="notification-badge hidden" id="notificationBadge">0</span>
            </div>
            <div class="notification-dropdown" id="notificationDropdown">
                <div class="notification-header">
                    <h3><i class="fas fa-bell"></i> Bildirimler</h3>
                    <button class="notification-clear-btn" id="notificationClearBtn">
                        <i class="fas fa-trash-alt"></i> Temizle
                    </button>
                </div>
                <div class="notification-list" id="notificationList"></div>
            </div>
        `;

        // Global notification alanını öncelikle kullan (her sayfada görünür)
        const globalContainer = document.getElementById('globalNotificationArea');
        const notificationContainer = document.getElementById('notificationArea') || document.getElementById('notificationContainer');
        const headerRight = document.querySelector('.header-right, .top-bar-right, .user-area');

        if (globalContainer) {
            globalContainer.appendChild(this.container);
        } else if (notificationContainer) {
            notificationContainer.appendChild(this.container);
        } else if (headerRight) {
            headerRight.insertBefore(this.container, headerRight.firstChild);
        } else {
            // Fallback: body'nin başına ekle (fixed position)
            document.body.insertBefore(this.container, document.body.firstChild);
            this.container.style.cssText = 'position: fixed; top: 16px; right: 24px; z-index: 9999;';
        }

        this.dropdown = document.getElementById('notificationDropdown');
        this.badge = document.getElementById('notificationBadge');
        this.list = document.getElementById('notificationList');

        this.renderList();
        this.updateBadge();
    },

    /**
     * Event listener'ları bağla
     */
    bindEvents() {
        const bell = document.getElementById('notificationBell');
        const clearBtn = document.getElementById('notificationClearBtn');

        bell.addEventListener('click', (e) => {
            e.stopPropagation();
            this.toggle();
        });

        clearBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            this.clearAll();
        });

        // Dışarı tıklamada kapat
        document.addEventListener('click', (e) => {
            if (this.isOpen && !this.container.contains(e.target)) {
                this.close();
            }
        });

        // ESC ile kapat
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && this.isOpen) {
                this.close();
            }
        });
    },

    /**
     * Dropdown aç/kapa
     */
    toggle() {
        if (this.isOpen) {
            this.close();
        } else {
            this.open();
        }
    },

    open() {
        this.isOpen = true;
        this.dropdown.classList.add('active');
        this.markAllAsRead();
    },

    close() {
        this.isOpen = false;
        this.dropdown.classList.remove('active');
    },

    /**
     * Bildirim listesini render et
     */
    renderList() {
        if (!this.list) return;

        if (this.notifications.length === 0) {
            this.list.innerHTML = `
                <div class="notification-empty">
                    <i class="fas fa-bell-slash"></i>
                    <p>Henüz bildirim yok</p>
                </div>
            `;
            return;
        }

        this.list.innerHTML = this.notifications
            .slice()
            .reverse()
            .map((n, idx) => this.renderItem(n, this.notifications.length - 1 - idx))
            .join('');

        // İtem tıklama event'leri
        this.list.querySelectorAll('.notification-item').forEach(item => {
            item.addEventListener('click', () => {
                const id = item.dataset.id;
                const notification = this.notifications.find(n => n.id === id);

                this.markAsRead(id);
                this.close();

                if (!notification) return;

                // v2.39.0: targetSection varsa o sekmeye git
                if (notification.targetSection === 'rag') {
                    this.navigateToRag();
                }
                // v2.24.6: Dialog ID varsa o dialog'u yükle
                else if (notification.dialogId) {
                    this.navigateToDialog(notification.dialogId);
                }
                // "Çözüm Önerisi" bildirimiyse dialog sekmesine git (v2.24.0)
                else if (notification.title.includes('Çözüm')) {
                    this.navigateToDialog();
                }
                else if (notification.title.includes('NGSSAI') || notification.title.includes('VYRA')) {
                    this.navigateToDialog();
                }
            });
        });
    },

    /**
     * v2.24.0: NGSSAI'ye Sor sekmesine git
     */
    navigateToTicket() {
        this.navigateToDialog();
    },

    /**
     * NGSSAI'ye Sor sekmesine git
     * v2.24.6: dialogId verilirse o dialog'un mesajlarını yükle
     * v2.26.1: DOM hazır olması için setTimeout eklendi
     */
    navigateToDialog(dialogId = null) {
        // Sidebar active state güncelle
        const allMenuItems = document.querySelectorAll('.menu-item');
        allMenuItems.forEach(item => item.classList.remove('active'));

        const homeBtn = document.getElementById('menuNewTicket');
        if (homeBtn) {
            homeBtn.classList.add('active');
        }

        // v2.24.6: Dialog ID varsa, sıfırlamadan o dialog'u yükle
        if (dialogId && window.DialogChatModule && typeof DialogChatModule.loadDialogById === 'function') {
            // Önce section'ı göster
            if (typeof showSection === 'function') {
                showSection('dialog', true); // skipLoad=true parametresi
            }
            // v2.26.1: DOM'un hazır olması için kısa gecikme
            setTimeout(() => {
                DialogChatModule.loadDialogById(dialogId);
                console.log('[NgssNotification] Dialog #' + dialogId + ' yükleniyor');
            }, 50);
        } else {
            // Normal davranış
            if (typeof showSection === 'function') {
                showSection('dialog');
                console.log('[NgssNotification] Dialog sekmesine yönlendirildi');
            } else {
                window.location.href = 'home.html';
            }
        }
    },

    /**
     * v2.39.0: Bilgi Tabanı (RAG) sekmesine git
     * Notification tıklanınca bilgi tabanı ekranına yönlendirir.
     */
    navigateToRag() {
        // Sidebar active state güncelle
        const allMenuItems = document.querySelectorAll('.menu-item');
        allMenuItems.forEach(item => item.classList.remove('active'));

        const ragBtn = document.getElementById('menuRAG');
        if (ragBtn) {
            ragBtn.classList.add('active');
        }

        if (typeof showSection === 'function') {
            showSection('rag');
            console.log('[NgssNotification] Bilgi Tabanı sekmesine yönlendirildi');
        } else {
            window.location.href = 'home.html';
        }
    },

    renderItem(notification, index) {
        const iconClass = this.getIconClass(notification.type);
        const timeAgo = this.getTimeAgo(notification.timestamp);
        const unreadClass = notification.read ? '' : 'unread';

        return `
            <div class="notification-item ${unreadClass}" data-id="${notification.id}">
                <div class="notification-icon ${notification.type}">
                    <i class="${iconClass}"></i>
                </div>
                <div class="notification-content">
                    <div class="notification-title">${this.escapeHtml(notification.title)}</div>
                    <div class="notification-message">${this.escapeHtml(notification.message)}</div>
                    <div class="notification-time">${timeAgo}</div>
                </div>
            </div>
        `;
    },

    getIconClass(type) {
        const icons = {
            success: 'fas fa-check-circle',
            error: 'fas fa-times-circle',
            warning: 'fas fa-exclamation-triangle',
            info: 'fas fa-info-circle'
        };
        return icons[type] || icons.info;
    },

    getTimeAgo(timestamp) {
        const now = Date.now();
        const diff = now - timestamp;
        const minutes = Math.floor(diff / 60000);
        const hours = Math.floor(diff / 3600000);
        const days = Math.floor(diff / 86400000);

        // Tarih ve saat formatı
        const date = new Date(timestamp);
        const timeStr = date.toLocaleTimeString('tr-TR', { hour: '2-digit', minute: '2-digit' });
        const dateStr = date.toLocaleDateString('tr-TR', { day: '2-digit', month: '2-digit', year: 'numeric' });

        // Bugün ise sadece saat
        const today = new Date();
        const isToday = date.toDateString() === today.toDateString();

        // Dün mü?
        const yesterday = new Date(today);
        yesterday.setDate(yesterday.getDate() - 1);
        const isYesterday = date.toDateString() === yesterday.toDateString();

        if (minutes < 1) return `Şimdi • ${timeStr}`;
        if (minutes < 60) return `${minutes} dk önce • ${timeStr}`;
        if (isToday) return `Bugün ${timeStr}`;
        if (isYesterday) return `Dün ${timeStr}`;
        if (days < 7) return `${days} gün önce • ${dateStr} ${timeStr}`;
        return `${dateStr} ${timeStr}`;
    },

    /**
     * Badge güncelle
     */
    updateBadge() {
        const unreadCount = this.notifications.filter(n => !n.read).length;

        if (unreadCount > 0) {
            this.badge.textContent = unreadCount > 99 ? '99+' : unreadCount;
            this.badge.classList.remove('hidden');
        } else {
            this.badge.classList.add('hidden');
        }
    },

    /**
     * Bildirim ekle
     * v2.24.6: dialogId parametresi eklendi
     * v2.39.0: targetSection parametresi eklendi (rag, dialog vb.)
     */
    add(type, title, message, dialogId = null, targetSection = null) {
        const notification = {
            id: Date.now().toString(),
            type,
            title,
            message,
            dialogId,  // v2.24.6: Dialog ID sakla
            targetSection,  // v2.39.0: Hedef sekme (örn: 'rag')
            timestamp: Date.now(),
            read: false
        };

        this.notifications.push(notification);

        // Max limit
        if (this.notifications.length > this.maxItems) {
            this.notifications = this.notifications.slice(-this.maxItems);
        }

        this.saveToStorage();
        this.renderList();
        this.updateBadge();

        return notification;
    },

    /**
     * Okundu olarak işaretle
     */
    markAsRead(id) {
        const notification = this.notifications.find(n => n.id === id);
        if (notification) {
            notification.read = true;
            this.saveToStorage();
            this.renderList();
            this.updateBadge();
        }
    },

    /**
     * Tümünü okundu işaretle
     */
    markAllAsRead() {
        this.notifications.forEach(n => n.read = true);
        this.saveToStorage();
        this.renderList();
        this.updateBadge();
    },

    /**
     * Tümünü temizle
     */
    clearAll() {
        this.notifications = [];
        this.saveToStorage();
        this.renderList();
        this.updateBadge();
    },

    /**
     * XSS koruması
     */
    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    },

    // Kısa yollar
    success(title, message) {
        return this.add('success', title, message);
    },

    error(title, message) {
        return this.add('error', title, message);
    },

    warning(title, message) {
        return this.add('warning', title, message);
    },

    info(title, message) {
        return this.add('info', title, message);
    }
};

// Auto-init
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => NgssNotification.init());
} else {
    NgssNotification.init();
}

// Global export
window.NgssNotification = NgssNotification;


