/**
 * VYRA - LDAP Settings Module
 * Admin panelinden LDAP sunucu ayarlarının CRUD yönetimi.
 * v2.46.0
 * @module LdapSettingsModule
 */
window.LdapSettingsModule = (function () {
    'use strict';

    const API_BASE = window.API_BASE_URL || 'http://localhost:8002';
    let editingId = null;
    let domainOrgData = []; // domain_org_permissions cache

    // ---------------------------------------------------------
    //  Helper: HTML escape (XSS koruması)
    // ---------------------------------------------------------
    function _esc(str) {
        if (!str) return '';
        const div = document.createElement('div');
        div.appendChild(document.createTextNode(String(str)));
        return div.innerHTML;
    }

    // ---------------------------------------------------------
    //  Helper: Auth header
    // ---------------------------------------------------------
    function authHeaders() {
        const token = localStorage.getItem('access_token');
        return {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
        };
    }

    // ---------------------------------------------------------
    //  Load LDAP Settings List
    // ---------------------------------------------------------
    async function load(companyId) {
        try {
            let url = `${API_BASE}/api/ldap-settings`;
            if (companyId) url += `?company_id=${companyId}`;
            const response = await fetch(url, {
                headers: authHeaders()
            });
            if (!response.ok) throw new Error('LDAP ayarları yüklenemedi');

            const data = await response.json();
            renderTable(data.settings || []);
        } catch (err) {
            console.error('[LDAP] Load error:', err);
            if (window.showToast) window.showToast('LDAP ayarları yüklenemedi', 'error');
        }
    }

    // ---------------------------------------------------------
    //  Render Table
    // ---------------------------------------------------------
    function renderTable(settings) {
        const tbody = document.getElementById('ldapSettingsBody');
        if (!tbody) return;

        if (!settings.length) {
            tbody.innerHTML = `
                <tr class="empty-row">
                    <td colspan="7">
                        <i class="fa-solid fa-inbox"></i>
                        Henüz LDAP sunucu tanımlanmamış
                    </td>
                </tr>`;
            return;
        }

        tbody.innerHTML = settings.map(s => `
            <tr>
                <td><span class="org-code-badge">${_esc(s.domain)}</span></td>
                <td>${_esc(s.display_name)}</td>
                <td class="text-mono">${_esc(s.url)}</td>
                <td class="text-mono text-sm">${_esc(s.search_base)}</td>
                <td>
                    <span class="status-badge ${s.enabled ? 'active' : 'inactive'}">
                        ${s.enabled ? 'Aktif' : 'Pasif'}
                    </span>
                </td>
                <td class="actions-cell">
                    <button class="btn-icon btn-test" title="Bağlantı Testi" onclick="LdapSettingsModule.testConnection(${parseInt(s.id, 10)})">
                        <i class="fa-solid fa-plug-circle-check"></i>
                    </button>
                    <button class="btn-icon btn-edit" title="Düzenle" onclick="LdapSettingsModule.openEdit(${parseInt(s.id, 10)})">
                        <i class="fa-solid fa-pen"></i>
                    </button>
                    <button class="btn-icon btn-delete" title="Sil" onclick="LdapSettingsModule.deleteSetting(${parseInt(s.id, 10)}, '${_esc(s.domain)}')">
                        <i class="fa-solid fa-trash"></i>
                    </button>
                </td>
            </tr>
        `).join('');
    }

    // ---------------------------------------------------------
    //  Fetch domain-org data from domain_org_permissions
    // ---------------------------------------------------------
    async function fetchDomainOrgs() {
        try {
            const resp = await fetch(`${API_BASE}/api/domain-org-permissions`, {
                headers: authHeaders()
            });
            if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
            domainOrgData = await resp.json();
        } catch (err) {
            console.warn('[LDAP] domain-org-permissions yukleme hatasi:', err);
            domainOrgData = [];
        }
    }

    function populateDomainDropdown(selectedDomain) {
        const sel = document.getElementById('ldapDomain');
        if (!sel) return;

        // Distinct domain'leri bul
        const domains = [...new Set(domainOrgData.map(d => d.domain))];

        sel.innerHTML = '<option value="">-- Domain Se\u00e7in --</option>';
        domains.forEach(d => {
            const opt = document.createElement('option');
            opt.value = d;
            opt.textContent = d;
            if (d === selectedDomain) opt.selected = true;
            sel.appendChild(opt);
        });
    }

    function renderOrgCheckboxes(domain, selectedOrgs) {
        const container = document.getElementById('ldapAllowedOrgsContainer');
        if (!container) return;

        const orgs = domainOrgData.filter(d => d.domain === domain).map(d => d.org_code);

        if (!domain || orgs.length === 0) {
            container.innerHTML = '<div class="ldap-org-empty">Domain se\u00e7ildi\u011finde organizasyonlar y\u00fcklenecek</div>';
            return;
        }

        const selected = selectedOrgs || [];
        container.innerHTML = orgs.map(org => {
            const checked = selected.includes(org) ? 'checked' : '';
            return `
                <label class="ldap-org-checkbox-item">
                    <input type="checkbox" name="ldapOrgCheck" value="${_esc(org)}" ${checked}>
                    <span class="ldap-org-checkbox-label">
                        <i class="fa-solid fa-building"></i> ${_esc(org)}
                    </span>
                </label>`;
        }).join('');
    }

    function getSelectedOrgs() {
        const checks = document.querySelectorAll('input[name="ldapOrgCheck"]:checked');
        return Array.from(checks).map(c => c.value);
    }

    // ---------------------------------------------------------
    //  Open Create Modal
    // ---------------------------------------------------------
    async function openCreate() {
        editingId = null;
        const titleEl = document.getElementById('ldapModalTitle');
        if (titleEl) titleEl.innerHTML = '<i class="fa-solid fa-network-wired"></i> Yeni LDAP Sunucu';

        await fetchDomainOrgs();
        populateDomainDropdown('');
        renderOrgCheckboxes('', []);

        // Firma dropdown'ı doldur
        const compSel = document.getElementById('ldapCompanyId');
        if (compSel && window.populateCompanySelect) {
            await window.populateCompanySelect(compSel, null);
            // Global selector'dan öntanımlı firma
            const globalSel = document.getElementById('globalCompanySelect');
            if (globalSel && globalSel.value) compSel.value = globalSel.value;
        }

        // Form temizle
        const domainSel = document.getElementById('ldapDomain');
        if (domainSel) { domainSel.value = ''; domainSel.disabled = false; }
        document.getElementById('ldapDisplayName').value = '';
        document.getElementById('ldapUrl').value = '';
        document.getElementById('ldapBindDn').value = '';
        document.getElementById('ldapBindPassword').value = '';
        document.getElementById('ldapSearchBase').value = '';
        document.getElementById('ldapSearchFilter').value = '(sAMAccountName={{username}})';
        document.getElementById('ldapUseSsl').value = 'false';
        document.getElementById('ldapEnabled').value = 'true';
        document.getElementById('ldapTimeout').value = '10';

        const hint = document.getElementById('ldapPasswordHint');
        if (hint) hint.classList.add('hidden');

        const modal = document.getElementById('ldapSettingModal');
        if (modal) modal.classList.remove('hidden');
    }

    // ---------------------------------------------------------
    //  Open Edit Modal
    // ---------------------------------------------------------
    async function openEdit(id) {
        editingId = id;

        try {
            await fetchDomainOrgs();

            // Listedeki verileri kullan
            const response = await fetch(`${API_BASE}/api/ldap-settings`, {
                headers: authHeaders()
            });
            const data = await response.json();
            const setting = (data.settings || []).find(s => s.id === id);

            if (!setting) {
                if (window.showToast) window.showToast('LDAP ayari bulunamadi', 'error');
                return;
            }

            // Firma dropdown'ı doldur (setting tanımlandıktan SONRA)
            const compSel = document.getElementById('ldapCompanyId');
            if (compSel && window.populateCompanySelect) {
                await window.populateCompanySelect(compSel, setting.company_id || null);
            }

            const titleEl = document.getElementById('ldapModalTitle');
            if (titleEl) titleEl.innerHTML = `<i class="fa-solid fa-network-wired"></i> ${_esc(setting.domain)} D\u00fczenle`;

            populateDomainDropdown(setting.domain);
            const domainSel = document.getElementById('ldapDomain');
            if (domainSel) { domainSel.value = setting.domain; domainSel.disabled = true; }
            renderOrgCheckboxes(setting.domain, setting.allowed_orgs || []);

            document.getElementById('ldapDisplayName').value = setting.display_name;
            document.getElementById('ldapUrl').value = setting.url;
            document.getElementById('ldapBindDn').value = setting.bind_dn;
            document.getElementById('ldapBindPassword').value = '';
            document.getElementById('ldapSearchBase').value = setting.search_base;
            document.getElementById('ldapSearchFilter').value = setting.search_filter || '(sAMAccountName={{username}})';
            document.getElementById('ldapUseSsl').value = setting.use_ssl ? 'true' : 'false';
            document.getElementById('ldapEnabled').value = setting.enabled ? 'true' : 'false';
            document.getElementById('ldapTimeout').value = setting.timeout || '10';

            // Sifre ipucu
            const hint = document.getElementById('ldapPasswordHint');
            if (hint) {
                if (setting.bind_password_set) {
                    hint.classList.remove('hidden');
                } else {
                    hint.classList.add('hidden');
                }
            }

            const modal = document.getElementById('ldapSettingModal');
            if (modal) modal.classList.remove('hidden');

        } catch (err) {
            console.error('[LDAP] Edit load error:', err);
            if (window.showToast) window.showToast('LDAP ayari yuklenemedi', 'error');
        }
    }

    // ---------------------------------------------------------
    //  Close Modal
    // ---------------------------------------------------------
    function closeModal() {
        const modal = document.getElementById('ldapSettingModal');
        if (modal) modal.classList.add('hidden');
        editingId = null;
    }

    // ---------------------------------------------------------
    //  Save (Create or Update)
    // ---------------------------------------------------------
    async function save() {
        const domain = document.getElementById('ldapDomain').value.trim().toUpperCase();
        const displayName = document.getElementById('ldapDisplayName').value.trim();
        const url = document.getElementById('ldapUrl').value.trim();
        const bindDn = document.getElementById('ldapBindDn').value.trim();
        const bindPassword = document.getElementById('ldapBindPassword').value;
        const searchBase = document.getElementById('ldapSearchBase').value.trim();
        const searchFilter = document.getElementById('ldapSearchFilter').value.trim();
        const allowedOrgs = getSelectedOrgs();
        const useSsl = document.getElementById('ldapUseSsl').value === 'true';
        const enabled = document.getElementById('ldapEnabled').value === 'true';
        const timeout = parseInt(document.getElementById('ldapTimeout').value, 10) || 10;

        // Validation
        if (!domain || !displayName || !url || !bindDn || !searchBase) {
            if (window.showToast) window.showToast('Zorunlu alanlari doldurun', 'error');
            return;
        }

        if (!editingId && !bindPassword) {
            if (window.showToast) window.showToast('Bind sifresi zorunludur', 'error');
            return;
        }

        const body = {
            display_name: displayName,
            url,
            bind_dn: bindDn,
            search_base: searchBase,
            search_filter: searchFilter || '(sAMAccountName={{username}})',
            allowed_orgs: allowedOrgs,
            use_ssl: useSsl,
            enabled,
            timeout
        };

        if (!editingId) body.domain = domain;
        if (bindPassword) body.bind_password = bindPassword;

        // Firma ID ekle
        const compSel = document.getElementById('ldapCompanyId');
        if (compSel && compSel.value) body.company_id = parseInt(compSel.value, 10);

        try {
            const method = editingId ? 'PUT' : 'POST';
            const endpoint = editingId
                ? `${API_BASE}/api/ldap-settings/${editingId}`
                : `${API_BASE}/api/ldap-settings`;

            const response = await fetch(endpoint, {
                method,
                headers: authHeaders(),
                body: JSON.stringify(body)
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.detail || 'İşlem başarısız');
            }

            if (window.showToast) window.showToast(data.message || 'Başarılı', 'success');
            closeModal();
            load();
        } catch (err) {
            console.error('[LDAP] Save error:', err);
            if (window.showToast) window.showToast(err.message, 'error');
        }
    }

    // ---------------------------------------------------------
    //  Delete Setting
    // ---------------------------------------------------------
    async function deleteSetting(id, domain) {
        VyraModal.danger({
            title: 'LDAP Sunucu Sil',
            message: `"${domain}" LDAP sunucusunu silmek istediğinize emin misiniz?`,
            confirmText: 'Sil',
            cancelText: 'İptal',
            onConfirm: async () => {
                try {
                    const response = await fetch(`${API_BASE}/api/ldap-settings/${id}`, {
                        method: 'DELETE',
                        headers: authHeaders()
                    });

                    const data = await response.json();
                    if (!response.ok) throw new Error(data.detail || 'Silme başarısız');

                    if (window.showToast) window.showToast(data.message || 'Silindi', 'success');
                    load();
                } catch (err) {
                    console.error('[LDAP] Delete error:', err);
                    if (window.showToast) window.showToast(err.message, 'error');
                }
            }
        });
    }

    // ---------------------------------------------------------
    //  Test Connection
    // ---------------------------------------------------------
    async function testConnection(id) {
        if (window.showToast) window.showToast('Bağlantı testi yapılıyor...', 'info');

        try {
            const response = await fetch(`${API_BASE}/api/ldap-settings/${id}/test`, {
                method: 'POST',
                headers: authHeaders()
            });

            const data = await response.json();

            if (data.success) {
                let stepsHtml = (data.steps || []).map(s =>
                    `<div style="padding:4px 0;font-size:13px">${s.status === 'success' ? '✅' : '❌'} <strong>${s.name}</strong>: ${s.message}</div>`
                ).join('');
                if (window.showToast) window.showToast(data.message, 'success');
                VyraModal.success({
                    title: 'LDAP Bağlantı Başarılı',
                    htmlMessage: `<div style="margin-top:8px">${stepsHtml}</div>`
                });
            } else {
                let stepsHtml = (data.steps || []).map(s =>
                    `<div style="padding:4px 0;font-size:13px">${s.status === 'success' ? '✅' : '❌'} <strong>${s.name}</strong>: ${s.message}</div>`
                ).join('');
                if (window.showToast) window.showToast(data.message, 'error');
                VyraModal.error({
                    title: 'LDAP Bağlantı Hatası',
                    htmlMessage: `<div style="margin-top:8px">${stepsHtml}</div>`
                });
            }
        } catch (err) {
            console.error('[LDAP] Test error:', err);
            if (window.showToast) window.showToast('Bağlantı testi başarısız', 'error');
        }
    }

    // ---------------------------------------------------------
    //  Init Event Listeners
    // ---------------------------------------------------------
    function init() {
        const btnNew = document.getElementById('btnNewLdapSetting');
        if (btnNew) btnNew.addEventListener('click', openCreate);

        const btnClose = document.getElementById('btnCloseLdapModal');
        if (btnClose) btnClose.addEventListener('click', closeModal);

        const btnCancel = document.getElementById('btnCancelLdap');
        if (btnCancel) btnCancel.addEventListener('click', closeModal);

        const btnSave = document.getElementById('btnSaveLdap');
        if (btnSave) btnSave.addEventListener('click', save);

        // Domain secildiginde org checkbox'larini guncelle
        const domainSel = document.getElementById('ldapDomain');
        if (domainSel) {
            domainSel.addEventListener('change', () => {
                renderOrgCheckboxes(domainSel.value, []);
            });
        }

        // ESC ile kapat
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                const modal = document.getElementById('ldapSettingModal');
                if (modal && !modal.classList.contains('hidden')) {
                    closeModal();
                }
            }
        });
    }

    // Auto-init
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

    // Public API
    return {
        load,
        openCreate,
        openEdit,
        closeModal,
        save,
        deleteSetting,
        testConnection,
        init
    };
})();


/* === assets/js/modules/org_permissions.js === */
/* ─────────────────────────────────────────────────
   NGSSAI — Organization Permissions Module
   Parametreler → Organizasyon Yetki sekmesi
   Domain ↔ Organizasyon yetki CRUD yönetimi
   v2.46.0
   ───────────────────────────────────────────────── */

window.OrgPermissionsModule = (function () {
    'use strict';

    const API_BASE = window.API_BASE_URL || 'http://localhost:8002';
    const ENDPOINT = `${API_BASE}/api/domain-org-permissions`;

    // Düzenleme modu state
    let editingId = null;

    // ── HTML Escape (XSS koruması) ──
    function _esc(str) {
        const d = document.createElement('div');
        d.textContent = str || '';
        return d.innerHTML;
    }

    // ── Load & Render ──
    let _currentCompanyId = null;

    async function load(companyId) {
        _currentCompanyId = companyId || null;
        try {
            const token = localStorage.getItem('access_token');
            let url = ENDPOINT;
            if (companyId) url += `?company_id=${companyId}`;
            const resp = await fetch(url, {
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (!resp.ok) throw new Error(`HTTP ${resp.status}`);

            const data = await resp.json();
            renderTable(data);
        } catch (err) {
            console.error('[OrgPermissions] Load error:', err);
            renderEmpty('Veriler yüklenirken hata oluştu');
        }
    }

    function renderTable(rows) {
        const tbody = document.getElementById('orgPermissionsBody');
        if (!tbody) return;

        if (!rows || rows.length === 0) {
            renderEmpty();
            return;
        }

        let html = '';
        let lastDomain = '';

        rows.forEach(row => {
            const isNewDomain = row.domain !== lastDomain;
            const groupClass = isNewDomain ? 'domain-group-first' : '';
            lastDomain = row.domain;

            html += `
                <tr class="${groupClass}" data-id="${parseInt(row.id, 10)}">
                    <td>
                        ${isNewDomain
                    ? `<span class="org-perm-domain-badge">
                                 <i class="fa-solid fa-network-wired"></i>
                                 ${_esc(row.domain)}
                               </span>`
                    : `<span class="org-perm-domain-badge" style="opacity: 0.3;">
                                 ${_esc(row.domain)}
                               </span>`
                }
                    </td>
                    <td>
                        <span class="org-perm-org-badge">
                            <i class="fa-solid fa-building"></i>
                            ${_esc(row.org_code)}
                        </span>
                    </td>
                    <td class="text-muted">${_esc(row.description || '-')}</td>
                    <td style="text-align: center;">
                        <div class="org-perm-actions">
                            <button class="btn-edit-org"
                                    data-id="${parseInt(row.id, 10)}"
                                    data-domain="${_esc(row.domain)}"
                                    data-org="${_esc(row.org_code)}"
                                    data-desc="${_esc(row.description || '')}"
                                    title="Düzenle">
                                <i class="fa-solid fa-pen"></i>
                            </button>
                            <button class="btn-delete-org"
                                    data-id="${parseInt(row.id, 10)}"
                                    title="Sil">
                                <i class="fa-solid fa-trash-can"></i>
                            </button>
                        </div>
                    </td>
                </tr>`;
        });

        tbody.innerHTML = html;

        // Event listeners
        tbody.querySelectorAll('.btn-delete-org').forEach(btn => {
            btn.addEventListener('click', () => handleDelete(btn.dataset.id));
        });
        tbody.querySelectorAll('.btn-edit-org').forEach(btn => {
            btn.addEventListener('click', () => startEdit(btn));
        });
    }

    function renderEmpty(msg) {
        const tbody = document.getElementById('orgPermissionsBody');
        if (!tbody) return;

        tbody.innerHTML = `
            <tr>
                <td colspan="4">
                    <div class="org-perm-empty">
                        <i class="fa-solid fa-shield-halved"></i>
                        <p>${_esc(msg || 'Henüz domain-organizasyon yetkisi tanımlanmamış')}</p>
                        <small>Yukarıdaki formu kullanarak yeni yetki ekleyebilirsiniz.</small>
                    </div>
                </td>
            </tr>`;
    }

    // ── Edit ──
    function startEdit(btn) {
        const id = btn.dataset.id;
        const domain = btn.dataset.domain;
        const org = btn.dataset.org;
        const desc = btn.dataset.desc;

        editingId = id;

        // Form alanlarını doldur
        const domainInput = document.getElementById('orgPermDomain');
        const orgInput = document.getElementById('orgPermOrgCode');
        const descInput = document.getElementById('orgPermDescription');
        const addBtn = document.getElementById('btnAddOrgPerm');
        const formTitle = document.getElementById('orgPermFormTitle');

        if (domainInput) domainInput.value = domain;
        if (orgInput) orgInput.value = org;
        if (descInput) descInput.value = desc;

        // Buton ve başlık güncelle
        if (addBtn) {
            addBtn.innerHTML = '<i class="fa-solid fa-save"></i> Güncelle';
            addBtn.classList.add('btn-update-mode');
        }
        if (formTitle) {
            formTitle.innerHTML = '<i class="fa-solid fa-pen-to-square"></i> Yetki Düzenle';
        }

        // İptal butonu göster
        showCancelBtn(true);

        // Satırı vurgula
        const tbody = document.getElementById('orgPermissionsBody');
        if (tbody) {
            tbody.querySelectorAll('tr').forEach(tr => tr.classList.remove('editing-row'));
            const editRow = tbody.querySelector(`tr[data-id="${id}"]`);
            if (editRow) editRow.classList.add('editing-row');
        }

        // Form'a odaklan
        if (domainInput) domainInput.focus();
    }

    function cancelEdit() {
        editingId = null;

        const domainInput = document.getElementById('orgPermDomain');
        const orgInput = document.getElementById('orgPermOrgCode');
        const descInput = document.getElementById('orgPermDescription');
        const addBtn = document.getElementById('btnAddOrgPerm');
        const formTitle = document.getElementById('orgPermFormTitle');

        if (domainInput) domainInput.value = '';
        if (orgInput) orgInput.value = '';
        if (descInput) descInput.value = '';

        if (addBtn) {
            addBtn.innerHTML = '<i class="fa-solid fa-plus"></i> Ekle';
            addBtn.classList.remove('btn-update-mode');
        }
        if (formTitle) {
            formTitle.innerHTML = '<i class="fa-solid fa-plus-circle"></i> Yeni Domain-Organizasyon Yetkisi Ekle';
        }

        showCancelBtn(false);

        // Satır vurgusunu kaldır
        const tbody = document.getElementById('orgPermissionsBody');
        if (tbody) {
            tbody.querySelectorAll('tr').forEach(tr => tr.classList.remove('editing-row'));
        }
    }

    function showCancelBtn(show) {
        let cancelBtn = document.getElementById('btnCancelOrgEdit');
        if (show && !cancelBtn) {
            const addBtn = document.getElementById('btnAddOrgPerm');
            if (addBtn) {
                cancelBtn = document.createElement('button');
                cancelBtn.id = 'btnCancelOrgEdit';
                cancelBtn.className = 'btn-cancel-edit';
                cancelBtn.innerHTML = '<i class="fa-solid fa-xmark"></i> İptal';
                cancelBtn.addEventListener('click', cancelEdit);
                addBtn.parentNode.insertBefore(cancelBtn, addBtn.nextSibling);
            }
        } else if (!show && cancelBtn) {
            cancelBtn.remove();
        }
    }

    // ── Add / Update ──
    async function handleAddOrUpdate() {
        const domainInput = document.getElementById('orgPermDomain');
        const orgInput = document.getElementById('orgPermOrgCode');
        const descInput = document.getElementById('orgPermDescription');

        const domain = (domainInput?.value || '').trim().toUpperCase();
        const orgCode = (orgInput?.value || '').trim().toUpperCase();
        const description = (descInput?.value || '').trim();

        if (!domain || !orgCode) {
            showToast('Domain ve Organizasyon alanları zorunludur.', 'error');
            return;
        }

        const addBtn = document.getElementById('btnAddOrgPerm');
        if (addBtn) { addBtn.disabled = true; }

        try {
            const token = localStorage.getItem('access_token');
            const isUpdate = editingId !== null;
            const url = isUpdate ? `${ENDPOINT}/${editingId}` : ENDPOINT;
            const method = isUpdate ? 'PUT' : 'POST';

            const payload = { domain, org_code: orgCode, description };
            if (_currentCompanyId) {
                payload.company_id = _currentCompanyId;
            }

            const resp = await fetch(url, {
                method,
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                },
                body: JSON.stringify(payload),
            });

            if (!resp.ok) {
                const err = await resp.json().catch(() => ({}));
                throw new Error(err.detail || `HTTP ${resp.status}`);
            }

            cancelEdit(); // Formu temizle ve normal moda dön
            showToast(
                isUpdate
                    ? `${domain} / ${orgCode} güncellendi.`
                    : `${domain} / ${orgCode} yetkisi eklendi.`,
                'success'
            );
            await load(_currentCompanyId);
        } catch (err) {
            console.error('[OrgPermissions] Save error:', err);
            showToast(err.message || 'İşlem başarısız.', 'error');
        } finally {
            if (addBtn) { addBtn.disabled = false; }
        }
    }

    // ── Delete ──
    async function handleDelete(id) {
        VyraModal.danger({
            title: 'Yetki Kaydını Sil',
            message: 'Bu yetki kaydını silmek istediğinize emin misiniz?',
            confirmText: 'Sil',
            cancelText: 'İptal',
            onConfirm: async () => {
                try {
                    const token = localStorage.getItem('access_token');
                    const resp = await fetch(`${ENDPOINT}/${id}`, {
                        method: 'DELETE',
                        headers: { 'Authorization': `Bearer ${token}` },
                    });

                    if (!resp.ok && resp.status !== 204) {
                        throw new Error(`HTTP ${resp.status}`);
                    }

                    // Eğer silinen satır düzenleniyorsa iptal et
                    if (editingId === String(id)) cancelEdit();

                    showToast('Yetki kaydı silindi.', 'success');
                    await load();
                } catch (err) {
                    console.error('[OrgPermissions] Delete error:', err);
                    showToast('Silme başarısız.', 'error');
                }
            }
        });
    }

    // ── Toast Helper ──
    function showToast(message, type) {
        if (window.NgssNotification) {
            if (type === 'error') {
                NgssNotification.error('İşlem Hatası', message);
            } else if (type === 'success') {
                NgssNotification.success('Başarılı', message);
            } else {
                NgssNotification.warning('Uyarı', message);
            }
        } else {
            console.log(`[OrgPermissions] ${type}: ${message}`);
        }
    }

    // ── Init ──
    function init() {
        const addBtn = document.getElementById('btnAddOrgPerm');
        if (addBtn) {
            addBtn.addEventListener('click', handleAddOrUpdate);
        }

        // Enter tuşu ile ekleme/güncelleme
        ['orgPermDomain', 'orgPermOrgCode', 'orgPermDescription'].forEach(id => {
            const el = document.getElementById(id);
            if (el) {
                el.addEventListener('keydown', (e) => {
                    if (e.key === 'Enter') {
                        e.preventDefault();
                        handleAddOrUpdate();
                    }
                    if (e.key === 'Escape' && editingId) {
                        cancelEdit();
                    }
                });
            }
        });
    }

    // Auto-init
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

    return { load, init };
})();


/* === assets/js/modules/widget_module.js === */
/**
 * NGSSAI Web Widget Yönetim Modülü
 * ==================================
 * Admin panelinde widget API anahtarlarını oluşturma,
 * listeleme, güncelleme ve silme işlemlerini yönetir.
 */

(function () {
    "use strict";

    const API_BASE = (window.API_BASE_URL || "http://localhost:8002") + "/api";

    function getToken() {
        return localStorage.getItem("access_token") || "";
    }

    function apiRequest(method, path, body) {
        return fetch(`${API_BASE}${path}`, {
            method,
            headers: {
                "Authorization": `Bearer ${getToken()}`,
                "Content-Type": "application/json",
            },
            body: body ? JSON.stringify(body) : undefined,
        });
    }

    // ------------------------------------------------------------------
    // State
    // ------------------------------------------------------------------
    let orgs = [];
    let keys = [];
    let widgetOptions = { prompts: [], llms: [] };

    // ------------------------------------------------------------------
    // Orgs yükle (select için)
    // ------------------------------------------------------------------
    async function loadOrgs() {
        try {
            const resp = await apiRequest("GET", "/organizations");
            if (resp.ok) {
                const data = await resp.json();
                orgs = data.organizations || data.items || (Array.isArray(data) ? data : []);
            }
        } catch (e) {
            console.error("[Widget] Orgs yüklenemedi:", e);
        }
    }

    function populateOrgSelect() {
        const sel = document.getElementById("widgetKeyOrg");
        if (!sel) return;
        sel.innerHTML = '<option value="">Organizasyon seçin...</option>';
        orgs
            .filter(o => o.is_active)
            .forEach(o => {
                const opt = document.createElement("option");
                opt.value = o.id;
                opt.textContent = `${o.org_name} (${o.org_code})`;
                sel.appendChild(opt);
            });
    }

    // ------------------------------------------------------------------
    // Options yükle (prompt & LLM select'leri için)
    // ------------------------------------------------------------------
    async function loadOptions() {
        try {
            const resp = await apiRequest("GET", "/widget/options");
            if (resp.ok) widgetOptions = await resp.json();
        } catch {}
    }

    function populatePromptSelect(selectedId) {
        const sel = document.getElementById("widgetKeyPrompt");
        if (!sel) return;
        sel.innerHTML = '<option value="">— Varsayılan sistem promptu kullan —</option>';
        (widgetOptions.prompts || []).forEach(p => {
            const opt = document.createElement("option");
            opt.value = p.id;
            opt.textContent = `${p.title} (${p.category})`;
            if (selectedId && p.id === selectedId) opt.selected = true;
            sel.appendChild(opt);
        });
    }

    function populateLlmSelect(selectedId) {
        const sel = document.getElementById("widgetKeyLlm");
        if (!sel) return;
        sel.innerHTML = '<option value="">— Varsayılan aktif model kullan —</option>';
        (widgetOptions.llms || []).forEach(l => {
            const opt = document.createElement("option");
            opt.value = l.id;
            opt.textContent = l.label;
            if (selectedId && l.id === selectedId) opt.selected = true;
            sel.appendChild(opt);
        });
    }

    // ------------------------------------------------------------------
    // Key listesini yükle ve tabloya render et
    // ------------------------------------------------------------------
    async function loadKeys(companyId) {
        const tbody = document.getElementById("widgetKeysTableBody");
        const empty = document.getElementById("widgetKeysEmpty");
        if (!tbody) return;

        tbody.innerHTML = `<tr><td colspan="8" style="text-align:center;color:var(--text-3);padding:32px">
            <i class="fa-solid fa-spinner fa-spin"></i> Yükleniyor...
        </td></tr>`;

        try {
            let keysUrl = "/widget/keys";
            if (companyId) keysUrl += `?company_id=${companyId}`;
            const resp = await apiRequest("GET", keysUrl);
            if (!resp.ok) throw new Error("Yüklenemedi");
            keys = await resp.json();
        } catch (e) {
            tbody.innerHTML = `<tr><td colspan="8" style="text-align:center;color:var(--red);padding:24px">
                Anahtarlar yüklenemedi: ${e.message}
            </td></tr>`;
            return;
        }

        if (!keys.length) {
            tbody.innerHTML = "";
            empty?.classList.remove("hidden");
            return;
        }

        empty?.classList.add("hidden");

        tbody.innerHTML = keys.map(k => {
            const domains = Array.isArray(k.allowed_domains) && k.allowed_domains.length
                ? k.allowed_domains.map(d => `<span class="badge badge-blue" style="font-size:10px">${d}</span>`).join(" ")
                : `<span style="color:var(--text-3);font-size:12px">Herkese açık</span>`;

            const lastUsed = k.last_used_at
                ? new Date(k.last_used_at).toLocaleDateString("tr-TR")
                : `<span style="color:var(--text-3)">Hiç</span>`;

            const statusBadge = k.is_active
                ? `<span class="badge badge-green"><span class="badge-dot"></span>Aktif</span>`
                : `<span class="badge badge-red"><span class="badge-dot"></span>Pasif</span>`;

            const ragBadge = k.use_rag !== false
                ? `<span class="badge badge-green" style="font-size:10px"><i class="fa-solid fa-database" style="margin-right:3px"></i>RAG</span>`
                : `<span class="badge" style="font-size:10px;background:var(--bg-3);color:var(--text-3)">Direkt LLM</span>`;
            const promptLabel = k.prompt_title
                ? `<span style="font-size:11px;color:var(--text-2);display:block;white-space:nowrap;max-width:130px;overflow:hidden;text-overflow:ellipsis" title="${escHtml(k.prompt_title)}"><i class="fa-solid fa-file-lines" style="margin-right:3px;opacity:.6"></i>${escHtml(k.prompt_title)}</span>`
                : "";
            const llmLabel = k.llm_model_name
                ? `<span style="font-size:11px;color:var(--text-2);display:block;white-space:nowrap;max-width:130px;overflow:hidden;text-overflow:ellipsis" title="${escHtml(k.llm_model_name)}"><i class="fa-solid fa-microchip" style="margin-right:3px;opacity:.6"></i>${escHtml(k.llm_model_name)}</span>`
                : "";

            return `
                <tr data-key-id="${k.id}">
                    <td style="font-weight:500;color:var(--text-1)">${escHtml(k.name)}</td>
                    <td><code style="font-family:monospace;font-size:12px;background:var(--bg-3);padding:2px 7px;border-radius:5px">${escHtml(k.key_prefix)}…</code></td>
                    <td><span class="badge badge-purple" style="font-size:11px">${escHtml(k.org_code)}</span></td>
                    <td>${domains}</td>
                    <td style="min-width:130px">${ragBadge}${promptLabel}${llmLabel}</td>
                    <td style="font-size:12px;color:var(--text-2)">${lastUsed}</td>
                    <td>${statusBadge}</td>
                    <td>
                        <div class="action-btns">
                            <button class="act-btn edit btn-toggle-key" data-key-id="${k.id}" data-active="${k.is_active}" title="${k.is_active ? 'Pasife Al' : 'Aktife Al'}">
                                <i class="fa-solid ${k.is_active ? 'fa-toggle-on' : 'fa-toggle-off'}"></i>
                            </button>
                            <button class="act-btn edit btn-snippet" data-key-id="${k.id}" title="Entegrasyon Kodunu Göster">
                                <i class="fa-solid fa-code"></i>
                            </button>
                            <button class="act-btn del btn-delete-key" data-key-id="${k.id}" title="Sil">
                                <i class="fa-solid fa-trash"></i>
                            </button>
                        </div>
                    </td>
                </tr>
            `;
        }).join("");

        // Event listeners
        tbody.querySelectorAll(".btn-toggle-key").forEach(btn => {
            btn.addEventListener("click", () => toggleKey(
                parseInt(btn.dataset.keyId),
                btn.dataset.active === "true"
            ));
        });

        tbody.querySelectorAll(".btn-snippet").forEach(btn => {
            btn.addEventListener("click", () => showSnippet(parseInt(btn.dataset.keyId)));
        });

        tbody.querySelectorAll(".btn-delete-key").forEach(btn => {
            btn.addEventListener("click", () => deleteKey(parseInt(btn.dataset.keyId)));
        });
    }

    // ------------------------------------------------------------------
    // Yeni key oluştur
    // ------------------------------------------------------------------
    async function openNewKeyModal() {
        const modal = document.getElementById("widgetKeyModal");
        if (!modal) return;
        populateOrgSelect();
        populatePromptSelect(null);
        populateLlmSelect(null);
        document.getElementById("widgetKeyName").value = "";
        document.getElementById("widgetKeyOrg").value = "";
        document.getElementById("widgetKeyDomains").value = "";
        document.getElementById("widgetKeyActive").checked = true;
        document.getElementById("widgetKeyUseRag").checked = true;

        // Firma dropdown'ı doldur (await ile beklenir)
        const compSel = document.getElementById('widgetCompanyId');
        if (compSel && window.populateCompanySelect) {
            await window.populateCompanySelect(compSel, null);
            const globalSel = document.getElementById('globalCompanySelect');
            if (globalSel && globalSel.value) compSel.value = globalSel.value;
        }

        modal.classList.remove("hidden");
    }

    function closeNewKeyModal() {
        document.getElementById("widgetKeyModal")?.classList.add("hidden");
    }

    async function saveWidgetKey() {
        const name = document.getElementById("widgetKeyName")?.value.trim();
        const orgId = parseInt(document.getElementById("widgetKeyOrg")?.value);
        const domainsRaw = document.getElementById("widgetKeyDomains")?.value.trim();
        const isActive = document.getElementById("widgetKeyActive")?.checked ?? true;
        const useRag = document.getElementById("widgetKeyUseRag")?.checked ?? true;
        const promptRaw = document.getElementById("widgetKeyPrompt")?.value;
        const llmRaw = document.getElementById("widgetKeyLlm")?.value;
        const promptId = promptRaw ? parseInt(promptRaw) : null;
        const llmConfigId = llmRaw ? parseInt(llmRaw) : null;

        if (!name) { showToast("Anahtar adı zorunludur", "error"); return; }
        if (!orgId) { showToast("Organizasyon seçin", "error"); return; }

        const companyIdEl = document.getElementById('widgetCompanyId');
        const companyIdVal = companyIdEl ? companyIdEl.value : '';

        const allowedDomains = domainsRaw
            ? domainsRaw.split(",").map(d => d.trim().toLowerCase()).filter(Boolean)
            : [];

        const saveBtn = document.getElementById("saveWidgetKey");
        if (saveBtn) { saveBtn.disabled = true; saveBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Oluşturuluyor...'; }

        try {
            const resp = await apiRequest("POST", "/widget/keys", {
                name, org_id: orgId, allowed_domains: allowedDomains, is_active: isActive,
                prompt_id: promptId, llm_config_id: llmConfigId, use_rag: useRag,
                company_id: companyIdVal ? parseInt(companyIdVal) : null,
            });

            if (!resp.ok) {
                const err = await resp.json().catch(() => ({}));
                throw new Error(err.detail || "Oluşturulamadı");
            }

            const data = await resp.json();
            closeNewKeyModal();
            showCreatedModal(data);
            await loadKeys();

        } catch (e) {
            showToast(e.message, "error");
        } finally {
            if (saveBtn) { saveBtn.disabled = false; saveBtn.innerHTML = '<i class="fa-solid fa-key"></i> Oluştur'; }
        }
    }

    // ------------------------------------------------------------------
    // Oluşturuldu modal
    // ------------------------------------------------------------------
    function showCreatedModal(data) {
        const modal = document.getElementById("widgetKeyCreatedModal");
        if (!modal) return;

        const keyInput = document.getElementById("widgetCreatedKey");
        const snippetEl = document.getElementById("widgetSnippet");
        const baseUrl = window.location.origin;

        if (keyInput) keyInput.value = data.api_key || "";
        if (snippetEl) {
            snippetEl.value = `<script src="${baseUrl}/widget/widget.js"\n        data-key="${data.api_key || ""}"\n        data-title="Destek Asistanı">\n<\/script>`;
        }

        modal.classList.remove("hidden");
    }

    function closeCreatedModal() {
        document.getElementById("widgetKeyCreatedModal")?.classList.add("hidden");
    }

    // ------------------------------------------------------------------
    // Snippet göster (mevcut key için)
    // ------------------------------------------------------------------
    function showSnippet(keyId) {
        const key = keys.find(k => k.id === keyId);
        if (!key) return;

        const baseUrl = window.location.origin;
        const snippet = `<script src="${baseUrl}/widget/widget.js"\n        data-key="${key.key_prefix}... (tam key'i kaydettiğiniz yerden alın)"\n        data-title="Destek Asistanı">\n<\/script>`;

        const createdModal = document.getElementById("widgetKeyCreatedModal");
        const keyInput = document.getElementById("widgetCreatedKey");
        const snippetEl = document.getElementById("widgetSnippet");

        if (keyInput) keyInput.value = `${key.key_prefix}... (güvenlik nedeniyle maskelendi)`;
        if (snippetEl) snippetEl.value = snippet;
        if (createdModal) createdModal.classList.remove("hidden");
    }

    // ------------------------------------------------------------------
    // Toggle aktif/pasif
    // ------------------------------------------------------------------
    async function toggleKey(keyId, currentlyActive) {
        try {
            const resp = await apiRequest("PUT", `/widget/keys/${keyId}`, {
                is_active: !currentlyActive,
            });
            if (!resp.ok) throw new Error("Güncellenemedi");
            showToast(`Anahtar ${!currentlyActive ? "aktifleştirildi" : "pasifleştirildi"}`, "success");
            await loadKeys();
        } catch (e) {
            showToast(e.message, "error");
        }
    }

    // ------------------------------------------------------------------
    // Key sil
    // ------------------------------------------------------------------
    async function deleteKey(keyId) {
        const key = keys.find(k => k.id === keyId);
        VyraModal.danger({
            title: 'Widget Anahtarını Sil',
            message: `"${key?.name || 'Bu anahtar'}" silinecek. Emin misiniz?`,
            confirmText: 'Sil',
            cancelText: 'İptal',
            onConfirm: async () => {
                try {
                    const resp = await apiRequest("DELETE", `/widget/keys/${keyId}`);
                    if (!resp.ok) throw new Error("Silinemedi");
                    showToast("Anahtar silindi", "success");
                    await loadKeys();
                } catch (e) {
                    showToast(e.message, "error");
                }
            }
        });
    }

    // ------------------------------------------------------------------
    // Clipboard kopyalama
    // ------------------------------------------------------------------
    function copyToClipboard(text, label) {
        navigator.clipboard?.writeText(text)
            .then(() => showToast(`${label} kopyalandı`, "success"))
            .catch(() => {
                const ta = document.createElement("textarea");
                ta.value = text;
                document.body.appendChild(ta);
                ta.select();
                document.execCommand("copy");
                ta.remove();
                showToast(`${label} kopyalandı`, "success");
            });
    }

    // ------------------------------------------------------------------
    // Toast / showToast uyumluluğu
    // ------------------------------------------------------------------
    function showToast(msg, type) {
        if (window.showToast) { window.showToast(msg, type); return; }
        const el = document.createElement("div");
        el.style.cssText = `position:fixed;bottom:24px;right:24px;z-index:9999;
            background:${type === "error" ? "#ef4444" : "#22c55e"};color:#fff;
            padding:10px 18px;border-radius:10px;font-size:13.5px;box-shadow:0 4px 16px rgba(0,0,0,.3)`;
        el.textContent = msg;
        document.body.appendChild(el);
        setTimeout(() => el.remove(), 3000);
    }

    // ------------------------------------------------------------------
    // HTML escape
    // ------------------------------------------------------------------
    function escHtml(s) {
        return String(s || "")
            .replace(/&/g, "&amp;").replace(/</g, "&lt;")
            .replace(/>/g, "&gt;").replace(/"/g, "&quot;");
    }

    // ------------------------------------------------------------------
    // Başlat — tab açıldığında çağrılır
    // ------------------------------------------------------------------
    async function init(companyId) {
        // base url span
        const baseUrlSpan = document.getElementById("widgetBaseUrl");
        if (baseUrlSpan) baseUrlSpan.textContent = window.location.origin;

        await Promise.all([loadOrgs(), loadOptions(), loadKeys(companyId)]);

        // Yeni Anahtar butonu
        document.getElementById("btnNewWidgetKey")
            ?.addEventListener("click", openNewKeyModal);

        // Modal kapat
        document.getElementById("closeWidgetKeyModal")
            ?.addEventListener("click", closeNewKeyModal);
        document.getElementById("cancelWidgetKeyModal")
            ?.addEventListener("click", closeNewKeyModal);

        // Modal kaydet
        document.getElementById("saveWidgetKey")
            ?.addEventListener("click", saveWidgetKey);

        // Oluşturuldu modal
        document.getElementById("closeWidgetCreatedModal")
            ?.addEventListener("click", closeCreatedModal);
        document.getElementById("closeWidgetCreatedOk")
            ?.addEventListener("click", closeCreatedModal);

        // Kopyala butonları
        document.getElementById("copyWidgetKey")?.addEventListener("click", () => {
            copyToClipboard(
                document.getElementById("widgetCreatedKey")?.value || "",
                "API anahtarı"
            );
        });
        document.getElementById("copyWidgetSnippet")?.addEventListener("click", () => {
            copyToClipboard(
                document.getElementById("widgetSnippet")?.value || "",
                "Entegrasyon kodu"
            );
        });

        // Overlay tıklamasıyla kapatma devre dışı (veri kaybı önleme)
        // Modallar yalnızca X/İptal butonu veya ESC ile kapatılır

        // ESC ile modal kapat
        document.addEventListener("keydown", (e) => {
            if (e.key === "Escape") {
                closeNewKeyModal();
                closeCreatedModal();
            }
        });
    }

    // Global erişim
    window.widgetModule = { init, loadKeys };

})();


/* === assets/js/modules/company_module.js === */
/* ----------------------------------
   VYRA - Company Module
   Firma yönetimi CRUD modülü (v2.59.0)
   app_name, theme_id branding desteği
---------------------------------- */

/**
 * CompanyModule - Firma CRUD, logo ve adres yönetimi
 * @module CompanyModule
 */
window.CompanyModule = (function () {
    'use strict';

    const API_BASE = window.API_BASE_URL || '';
    let companies = [];
    let editingId = null;
    let addressCache = { provinces: null, districts: {}, neighborhoods: {} };
    let themesList = []; // v2.59.0: Tema listesi cache

    // --- Token helper ---
    function getToken() {
        return localStorage.getItem('access_token') || '';
    }

    function authHeaders() {
        return {
            'Authorization': 'Bearer ' + getToken(),
            'Content-Type': 'application/json'
        };
    }

    // --- API Çağrıları ---

    async function fetchCompanies() {
        try {
            const res = await fetch(API_BASE + '/api/companies/', {
                headers: authHeaders()
            });
            if (!res.ok) throw new Error('Firma listesi alınamadı');
            companies = await res.json();
            return companies;
        } catch (err) {
            console.error('[CompanyModule] fetch error:', err);
            return [];
        }
    }

    async function saveCompany(data) {
        const url = editingId
            ? API_BASE + '/api/companies/' + editingId
            : API_BASE + '/api/companies/';
        const method = editingId ? 'PUT' : 'POST';

        const res = await fetch(url, {
            method: method,
            headers: authHeaders(),
            body: JSON.stringify(data)
        });

        if (!res.ok) {
            const err = await res.json().catch(() => ({}));
            throw new Error(err.detail || 'Kaydetme hatası');
        }
        return await res.json();
    }

    async function deleteCompany(id) {
        const res = await fetch(API_BASE + '/api/companies/' + id, {
            method: 'DELETE',
            headers: authHeaders()
        });
        if (!res.ok) {
            const err = await res.json().catch(() => ({}));
            throw new Error(err.detail || 'Silme hatası');
        }
        return await res.json();
    }

    async function uploadLogo(companyId, file) {
        const formData = new FormData();
        formData.append('file', file);

        const res = await fetch(API_BASE + '/api/companies/' + companyId + '/logo', {
            method: 'POST',
            headers: { 'Authorization': 'Bearer ' + getToken() },
            body: formData
        });
        if (!res.ok) {
            const err = await res.json().catch(() => ({}));
            throw new Error(err.detail || 'Logo yükleme hatası');
        }
        return await res.json();
    }

    // --- Tema API (v2.60.0 → v2.60.1 UX fix) ---

    let assignedThemeIds = new Set();
    let selectedDefaultThemeId = null;  // v2.60.1: Kullanıcının seçtiği varsayılan tema

    async function fetchThemesFull() {
        try {
            const res = await fetch(API_BASE + '/api/themes/full', {
                headers: authHeaders()
            });
            if (!res.ok) return [];
            themesList = await res.json();
            return themesList;
        } catch (err) {
            console.warn('[CompanyModule] Tema listesi alınamadı:', err);
            return [];
        }
    }

    async function fetchAssignedThemes(companyId) {
        if (!companyId) return [];
        try {
            const res = await fetch(API_BASE + '/api/themes/company/' + companyId, {
                headers: authHeaders()
            });
            if (!res.ok) return [];
            return await res.json();
        } catch (err) {
            console.warn('[CompanyModule] Atanmış temalar alınamadı:', err);
            return [];
        }
    }

    function renderThemeCard(theme, isAssigned, isDefault, mode) {
        var colors = theme.preview_colors || [];
        if (typeof colors === 'string') {
            try { colors = JSON.parse(colors); } catch(e) { colors = ['#666','#999']; }
        }
        var c1 = colors[0] || '#666';
        var c2 = colors[1] || '#999';
        // mode: 'pool' = havuz kartı, 'assigned' = atanmış kart
        var extraBtns = '';
        if (mode === 'assigned') {
            extraBtns = '<div class="design-card-actions">' +
                '<button type="button" class="design-card-default-btn' + (isDefault ? ' active' : '') + '" data-default-theme="' + theme.id + '" title="Varsayılan Yap">★</button>' +
                '<button type="button" class="design-card-remove-btn" data-remove-theme="' + theme.id + '" title="Kaldır">✕</button>' +
            '</div>';
        }
        return '<div class="design-theme-card ' + (isAssigned ? 'selected' : '') + '" data-theme-id="' + theme.id + '">' +
            '<div class="dt-check">✓</div>' +
            '<div class="dt-swatch">' +
                '<div class="dt-swatch-half" style="background:' + c1 + '"></div>' +
                '<div class="dt-swatch-half" style="background:' + c2 + '"></div>' +
            '</div>' +
            '<div class="dt-name">' + escapeHtml(theme.name) + '</div>' +
            (isDefault ? '<div class="dt-check dt-check-default">★</div>' : '') +
            extraBtns +
        '</div>';
    }

    /**
     * Atanmış temalar grid'ini güncel Set'e göre yeniden render eder (v2.60.1)
     */
    function updateAssignedGrid() {
        var assignedGrid = document.getElementById('companyAssignedThemes');
        if (!assignedGrid) return;

        if (assignedThemeIds.size === 0) {
            assignedGrid.innerHTML = '<p class="design-empty-hint">Henüz tema atanmadı. Aşağıdan tema seçin.</p>';
            selectedDefaultThemeId = null;
        } else {
            // Default tema kontrolü: eğer mevcut default kaldırıldıysa ilkini default yap
            if (!selectedDefaultThemeId || !assignedThemeIds.has(selectedDefaultThemeId)) {
                selectedDefaultThemeId = Array.from(assignedThemeIds)[0];
            }
            var html = '';
            assignedThemeIds.forEach(function(tid) {
                var t = themesList.find(function(th) { return th.id === tid; });
                if (t) html += renderThemeCard(t, true, tid === selectedDefaultThemeId, 'assigned');
            });
            assignedGrid.innerHTML = html;

            // Kaldır butonu
            assignedGrid.querySelectorAll('[data-remove-theme]').forEach(function(btn) {
                btn.addEventListener('click', function(e) {
                    e.stopPropagation();
                    var tid = parseInt(this.getAttribute('data-remove-theme'), 10);
                    var theme = themesList.find(function(th) { return th.id === tid; });
                    assignedThemeIds.delete(tid);
                    updateAssignedGrid();
                    updatePoolGrid();
                    syncHiddenInput();
                    if (window.VyraToast && theme) VyraToast.info(theme.name + ' kaldırıldı');
                });
            });

            // Varsayılan yap butonu
            assignedGrid.querySelectorAll('[data-default-theme]').forEach(function(btn) {
                btn.addEventListener('click', function(e) {
                    e.stopPropagation();
                    var tid = parseInt(this.getAttribute('data-default-theme'), 10);
                    selectedDefaultThemeId = tid;
                    var theme = themesList.find(function(th) { return th.id === tid; });
                    updateAssignedGrid();
                    syncHiddenInput();
                    if (window.VyraToast && theme) VyraToast.success(theme.name + ' varsayılan yapıldı');
                });
            });
        }
    }

    /**
     * Havuz grid'ini güncel Set'e göre yeniden render eder (v2.60.1)
     */
    function updatePoolGrid() {
        var poolGrid = document.getElementById('companyThemePool');
        if (!poolGrid) return;

        poolGrid.innerHTML = themesList.map(function(t) {
            return renderThemeCard(t, assignedThemeIds.has(t.id), t.id === selectedDefaultThemeId, 'pool');
        }).join('');

        // Kart tıklama — toggle selection
        poolGrid.querySelectorAll('.design-theme-card').forEach(function(card) {
            card.addEventListener('click', function() {
                var tid = parseInt(this.getAttribute('data-theme-id'), 10);
                var theme = themesList.find(function(th) { return th.id === tid; });
                if (assignedThemeIds.has(tid)) {
                    assignedThemeIds.delete(tid);
                    if (window.VyraToast && theme) VyraToast.info(theme.name + ' kaldırıldı');
                } else {
                    assignedThemeIds.add(tid);
                    if (window.VyraToast && theme) VyraToast.info(theme.name + ' eklendi');
                }
                updateAssignedGrid();
                updatePoolGrid();
                syncHiddenInput();
            });
        });
    }

    /**
     * Hidden input'u güncel default tema ile senkronize eder
     */
    function syncHiddenInput() {
        var hiddenInput = document.getElementById('companyThemeId');
        if (hiddenInput) hiddenInput.value = selectedDefaultThemeId || '';
    }

    async function renderDesignTab(companyId) {
        // Temaları yükle
        if (themesList.length === 0) await fetchThemesFull();

        // Firmaya atanmış temaları yükle
        var assigned = companyId ? await fetchAssignedThemes(companyId) : [];
        assignedThemeIds = new Set(assigned.map(function(a) { return a.id; }));
        selectedDefaultThemeId = null;
        assigned.forEach(function(a) { if (a.is_default) selectedDefaultThemeId = a.id; });

        // Atanmış temalar grid (v2.60.1: updateAssignedGrid kullan)
        updateAssignedGrid();

        // Tema havuzu grid (v2.60.1: updatePoolGrid kullan)
        updatePoolGrid();

        // Color picker önizleme
        var c1Input = document.getElementById('newThemeColor1');
        var c2Input = document.getElementById('newThemeColor2');
        if (c1Input && c2Input) {
            var updatePreview = function() {
                var h1 = document.getElementById('newThemePreviewHalf1');
                var h2 = document.getElementById('newThemePreviewHalf2');
                if (h1) h1.style.background = c1Input.value;
                if (h2) h2.style.background = c2Input.value;
            };
            c1Input.addEventListener('input', updatePreview);
            c2Input.addEventListener('input', updatePreview);
            updatePreview(); // v2.60.1: Başlangıç renklerini hemen uygula
        }

        // Öner butonu
        var suggestBtn = document.getElementById('btnSuggestColors');
        if (suggestBtn) {
            suggestBtn.onclick = async function() {
                var color = c1Input ? c1Input.value : '#06B6D4';
                try {
                    var res = await fetch(API_BASE + '/api/themes/suggest', {
                        method: 'POST',
                        headers: { ...authHeaders(), 'Content-Type': 'application/json' },
                        body: JSON.stringify({ color: color })
                    });
                    if (!res.ok) throw new Error('Öneri alınamadı');
                    var data = await res.json();
                    renderSuggestions(data.suggestions || []);
                } catch (err) {
                    console.error('[CompanyModule] Öneri hatası:', err);
                }
            };
        }

        // Yeni tema kaydet
        var saveBtn = document.getElementById('btnSaveNewTheme');
        if (saveBtn) {
            saveBtn.onclick = async function() {
                var name = (document.getElementById('newThemeName') || {}).value;
                var color1 = c1Input ? c1Input.value : '#06B6D4';
                var color2 = c2Input ? c2Input.value : '#3B82F6';
                if (!name) {
                    if (window.VyraToast) VyraToast.warning('Lütfen tema adı girin');
                    return;
                }
                try {
                    var res = await fetch(API_BASE + '/api/themes/', {
                        method: 'POST',
                        headers: { ...authHeaders(), 'Content-Type': 'application/json' },
                        body: JSON.stringify({ name: name, color1: color1, color2: color2, company_id: editingId })
                    });
                    if (!res.ok) {
                        var err = await res.json().catch(function() { return {}; });
                        throw new Error(err.detail || 'Tema oluşturulamadı');
                    }
                    if (window.VyraToast) VyraToast.success('Tema oluşturuldu: ' + name);
                    // Listeyi yenile
                    themesList = [];
                    await renderDesignTab(editingId);
                } catch (err) {
                    if (window.VyraToast) VyraToast.error(err.message);
                }
            };
        }
    }

    function renderSuggestions(suggestions) {
        var container = document.getElementById('colorSuggestions');
        if (!container) return;
        container.classList.remove('hidden');
        container.innerHTML = suggestions.map(function(s) {
            return '<div class="design-suggest-card ' + (s.already_exists ? 'exists' : '') + '" data-c1="' + s.color1 + '" data-c2="' + s.color2 + '">' +
                '<div class="ds-swatch">' +
                    '<div class="ds-swatch-half" style="background:' + s.color1 + '"></div>' +
                    '<div class="ds-swatch-half" style="background:' + s.color2 + '"></div>' +
                '</div>' +
                '<div class="ds-label">' + s.label + (s.already_exists ? ' ✕' : '') + '</div>' +
            '</div>';
        }).join('');

        // Kart tıklama — renkleri color picker'a ata
        container.querySelectorAll('.design-suggest-card:not(.exists)').forEach(function(card) {
            card.addEventListener('click', function() {
                var c1 = this.getAttribute('data-c1');
                var c2 = this.getAttribute('data-c2');
                var inp1 = document.getElementById('newThemeColor1');
                var inp2 = document.getElementById('newThemeColor2');
                if (inp1) { inp1.value = c1; }
                if (inp2) { inp2.value = c2; }
                var h1 = document.getElementById('newThemePreviewHalf1');
                var h2 = document.getElementById('newThemePreviewHalf2');
                if (h1) h1.style.background = c1;
                if (h2) h2.style.background = c2;
            });
        });
    }

    // v2.59.0 eski fonksiyonlar (uyumluluk)
    function populateThemeSelect(selectedId) {
        var hiddenInput = document.getElementById('companyThemeId');
        if (hiddenInput && selectedId) hiddenInput.value = selectedId;
    }

    // --- Türkiye Adres API ---

    async function loadProvinces() {
        const select = document.getElementById('companyAddressIl');
        if (!select) return;

        // Cache varsa kullan
        if (addressCache.provinces) {
            populateSelect(select, addressCache.provinces, 'İl Seçin...');
            return;
        }

        select.innerHTML = '<option value="">Yükleniyor...</option>';
        try {
            const res = await fetch(API_BASE + '/api/address/provinces');
            if (!res.ok) throw new Error('İl listesi alınamadı');
            const data = (await res.json())
                .map(p => ({ value: p.name, label: p.name, id: p.id }))
                .sort((a, b) => a.label.localeCompare(b.label, 'tr'));
            addressCache.provinces = data;
            populateSelect(select, data, 'İl Seçin...');
        } catch (err) {
            console.warn('[CompanyModule] İl API hatası:', err);
            select.innerHTML = '<option value="">İl Seçin (veri yüklenmedi)...</option>';
        }
    }

    async function loadDistricts(provinceName) {
        const select = document.getElementById('companyAddressIlce');
        const mahalleSelect = document.getElementById('companyAddressMahalle');
        if (!select) return;

        // Mahalle temizle
        if (mahalleSelect) {
            mahalleSelect.innerHTML = '<option value="">Önce ilçe seçin...</option>';
            mahalleSelect.disabled = true;
        }

        if (!provinceName) {
            select.innerHTML = '<option value="">Önce il seçin...</option>';
            select.disabled = true;
            return;
        }

        // İl ID'sini bul
        const province = (addressCache.provinces || []).find(p => p.value === provinceName);
        if (!province) return;

        // Cache varsa kullan
        if (addressCache.districts[province.id]) {
            populateSelect(select, addressCache.districts[province.id], 'İlçe Seçin...');
            select.disabled = false;
            return;
        }

        select.innerHTML = '<option value="">Yükleniyor...</option>';
        select.disabled = true;

        try {
            const res = await fetch(API_BASE + '/api/address/districts/' + province.id);
            if (!res.ok) throw new Error('İlçe listesi alınamadı');
            const districts = (await res.json())
                .map(d => ({ value: d.name, label: d.name, id: d.id }))
                .sort((a, b) => a.label.localeCompare(b.label, 'tr'));
            addressCache.districts[province.id] = districts;
            populateSelect(select, districts, 'İlçe Seçin...');
            select.disabled = false;
        } catch (err) {
            console.warn('[CompanyModule] İlçe API hatası:', err);
            select.innerHTML = '<option value="">İlçe Seçin (veri yüklenmedi)...</option>';
            select.disabled = false;
        }
    }

    async function loadNeighborhoods(provinceName, districtName) {
        const select = document.getElementById('companyAddressMahalle');
        if (!select) return;

        if (!districtName) {
            select.innerHTML = '<option value="">Önce ilçe seçin...</option>';
            select.disabled = true;
            return;
        }

        // İlçe ID'sini bul
        const province = (addressCache.provinces || []).find(p => p.value === provinceName);
        if (!province) return;
        const district = (addressCache.districts[province.id] || []).find(d => d.value === districtName);
        if (!district) return;

        // Cache varsa kullan
        const cacheKey = province.id + '_' + district.id;
        if (addressCache.neighborhoods[cacheKey]) {
            populateSelect(select, addressCache.neighborhoods[cacheKey], 'Mahalle Seçin...');
            select.disabled = false;
            return;
        }

        select.innerHTML = '<option value="">Yükleniyor...</option>';
        select.disabled = true;

        try {
            const res = await fetch(API_BASE + '/api/address/neighborhoods/' + district.id);
            if (!res.ok) throw new Error('Mahalle listesi alınamadı');
            const neighborhoods = (await res.json())
                .map(n => ({ value: n.name, label: n.name }))
                .sort((a, b) => a.label.localeCompare(b.label, 'tr'));
            addressCache.neighborhoods[cacheKey] = neighborhoods;
            populateSelect(select, neighborhoods, 'Mahalle Seçin...');
            select.disabled = false;
        } catch (err) {
            console.warn('[CompanyModule] Mahalle API hatası:', err);
            select.innerHTML = '<option value="">Mahalle Seçin (veri yüklenmedi)...</option>';
            select.disabled = false;
        }
    }

    function populateSelect(select, items, placeholder) {
        let html = '<option value="">' + placeholder + '</option>';
        items.forEach(item => {
            html += '<option value="' + escapeHtml(item.value) + '">' + escapeHtml(item.label) + '</option>';
        });
        select.innerHTML = html;
    }

    // --- Render ---

    function render() {
        const grid = document.getElementById('companyGrid');
        const empty = document.getElementById('companyEmptyState');
        if (!grid) return;

        if (!companies || companies.length === 0) {
            grid.innerHTML = '';
            if (empty) {
                grid.appendChild(empty);
                empty.style.display = '';
            }
            return;
        }

        // empty state gizle
        if (empty) empty.style.display = 'none';

        const cards = companies.map(c => {
            const logoUrl = c.has_logo
                ? (API_BASE + '/api/companies/' + c.id + '/logo')
                : '';
            const taxLabel = c.tax_type === 'tckn' ? 'TCKN' : 'VD';
            const statusBadge = c.is_active
                ? '<span class="company-badge active"><i class="fa-solid fa-circle"></i> Aktif</span>'
                : '<span class="company-badge inactive"><i class="fa-solid fa-circle"></i> Pasif</span>';

            return `
            <div class="company-card" data-id="${c.id}">
                <div class="company-card-top">
                    <div class="company-logo-wrap">
                        ${logoUrl
                            ? '<img src="' + logoUrl + '" alt="Logo" class="company-logo-img" onerror="this.style.display=\'none\';this.nextElementSibling.style.display=\'flex\'"><div class="company-logo-placeholder" style="display:none"><i class="fa-solid fa-building"></i></div>'
                            : '<div class="company-logo-placeholder"><i class="fa-solid fa-building"></i></div>'
                        }
                    </div>
                    <div class="company-card-actions">
                        ${statusBadge}
                        <button class="btn-icon" title="Düzenle" data-company-edit="${c.id}">
                            <i class="fa-solid fa-pen"></i>
                        </button>
                        <button class="btn-icon btn-icon-danger" title="Deaktif Et" data-company-delete="${c.id}">
                            <i class="fa-solid fa-trash"></i>
                        </button>
                    </div>
                </div>
                <div class="company-card-body">
                    <h3 class="company-name">${escapeHtml(c.name)}</h3>
                    <div class="company-meta-grid">
                        <div class="company-meta-item">
                            <i class="fa-solid fa-hashtag"></i>
                            <span>${taxLabel}: ${escapeHtml(c.tax_number)}</span>
                        </div>
                        <div class="company-meta-item">
                            <i class="fa-solid fa-phone"></i>
                            <span>${escapeHtml(c.phone)}</span>
                        </div>
                        <div class="company-meta-item">
                            <i class="fa-solid fa-envelope"></i>
                            <span>${escapeHtml(c.email)}</span>
                        </div>
                        ${c.website ? `
                        <div class="company-meta-item">
                            <i class="fa-solid fa-globe"></i>
                            <span><a href="${escapeHtml(c.website)}" target="_blank" class="company-website-link">${escapeHtml(c.website)}</a></span>
                        </div>` : ''}
                        <div class="company-meta-item">
                            <i class="fa-solid fa-user-tie"></i>
                            <span>${escapeHtml(c.contact_name)} ${escapeHtml(c.contact_surname)}</span>
                        </div>
                        ${c.address_il ? `
                        <div class="company-meta-item">
                            <i class="fa-solid fa-location-dot"></i>
                            <span>${escapeHtml(c.address_il)}${c.address_ilce ? ' / ' + escapeHtml(c.address_ilce) : ''}</span>
                        </div>` : ''}
                    </div>
                </div>
            </div>`;
        }).join('');

        grid.innerHTML = cards;
    }

    function escapeHtml(text) {
        if (!text) return '';
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    // --- Modal ---

    async function openModal(companyId) {
        editingId = companyId || null;
        const modal = document.getElementById('companyModal');
        if (!modal) return;

        const title = document.getElementById('companyModalTitle');
        const form = document.getElementById('companyForm');

        if (title) {
            title.innerHTML = companyId
                ? '<i class="fa-solid fa-building"></i> Firma Düzenle'
                : '<i class="fa-solid fa-building"></i> Yeni Firma Ekle';
        }

        // Form temizle
        if (form) form.reset();

        // Logo preview temizle
        const preview = document.getElementById('companyLogoPreview');
        if (preview) preview.innerHTML = '';

        // Tax type default
        const taxTypeSelect = document.getElementById('companyTaxType');
        if (taxTypeSelect) taxTypeSelect.value = 'vd';

        // İlçe ve Mahalle resetle
        const ilceSelect = document.getElementById('companyAddressIlce');
        const mahalleSelect = document.getElementById('companyAddressMahalle');
        if (ilceSelect) { ilceSelect.innerHTML = '<option value="">Önce il seçin...</option>'; ilceSelect.disabled = true; }
        if (mahalleSelect) { mahalleSelect.innerHTML = '<option value="">Önce ilçe seçin...</option>'; mahalleSelect.disabled = true; }

        // İl listesini yükle
        await loadProvinces();

        // Tasarım sekmesi (v2.60.0)
        await renderDesignTab(companyId);

        if (companyId) {
            // Düzenleme — mevcut verileri doldur
            const company = companies.find(c => c.id === companyId);
            if (company) {
                setField('companyName', company.name);
                setField('companyAppName', company.app_name);
                if (taxTypeSelect) taxTypeSelect.value = company.tax_type || 'vd';
                setField('companyTaxNumber', company.tax_number);
                setField('companyAddressText', company.address_text);
                setField('companyPhone', company.phone);
                setField('companyEmail', company.email);
                setField('companyWebsite', company.website);
                setField('companyContactName', company.contact_name);
                setField('companyContactSurname', company.contact_surname);

                // Adres dropdown'larını cascade olarak yükle
                if (company.address_il) {
                    setField('companyAddressIl', company.address_il);
                    await loadDistricts(company.address_il);
                    if (company.address_ilce) {
                        setField('companyAddressIlce', company.address_ilce);
                        await loadNeighborhoods(company.address_il, company.address_ilce);
                        if (company.address_mahalle) {
                            setField('companyAddressMahalle', company.address_mahalle);
                        }
                    }
                }

                // Logo preview (v2.60.1: onerror fallback)
                if (company.has_logo && preview) {
                    var logoImg = document.createElement('img');
                    logoImg.src = API_BASE + '/api/companies/' + company.id + '/logo';
                    logoImg.alt = 'Logo';
                    logoImg.className = 'company-logo-preview-img';
                    logoImg.onerror = function() { preview.innerHTML = '<div class="company-logo-placeholder"><i class="fa-solid fa-building"></i></div>'; };
                    preview.innerHTML = '';
                    preview.appendChild(logoImg);
                }
            }
        }

        modal.classList.remove('hidden');
    }

    function closeModal() {
        const modal = document.getElementById('companyModal');
        if (modal) modal.classList.add('hidden');
        editingId = null;
    }

    function setField(id, value) {
        const el = document.getElementById(id);
        if (el) el.value = value || '';
    }

    // --- Save Handler ---

    async function handleSave() {
        // v2.59.0: app_name ve theme_id eklendi
        const themeVal = (document.getElementById('companyThemeId') || {}).value;
        const data = {
            name: (document.getElementById('companyName') || {}).value || '',
            app_name: (document.getElementById('companyAppName') || {}).value || null,
            theme_id: themeVal ? parseInt(themeVal, 10) : null,
            tax_type: (document.getElementById('companyTaxType') || {}).value || 'vd',
            tax_number: (document.getElementById('companyTaxNumber') || {}).value || '',
            address_il: (document.getElementById('companyAddressIl') || {}).value || null,
            address_ilce: (document.getElementById('companyAddressIlce') || {}).value || null,
            address_mahalle: (document.getElementById('companyAddressMahalle') || {}).value || null,
            address_text: (document.getElementById('companyAddressText') || {}).value || null,
            phone: (document.getElementById('companyPhone') || {}).value || '',
            email: (document.getElementById('companyEmail') || {}).value || '',
            website: (document.getElementById('companyWebsite') || {}).value || null,
            contact_name: (document.getElementById('companyContactName') || {}).value || '',
            contact_surname: (document.getElementById('companyContactSurname') || {}).value || ''
        };

        // Validasyon
        if (!data.name || !data.tax_number || !data.phone || !data.email || !data.contact_name || !data.contact_surname) {
            if (typeof Swal !== 'undefined') {
                Swal.fire('Uyarı', 'Zorunlu alanları doldurun.', 'warning');
            }
            return;
        }

        try {
            const result = await saveCompany(data);

            // Logo dosyası seçildiyse yükle
            const logoInput = document.getElementById('companyLogoFile');
            if (logoInput && logoInput.files && logoInput.files[0]) {
                const companyId = result.id || editingId;
                await uploadLogo(companyId, logoInput.files[0]);
            }

            // v2.60.0: Tema atamaları kaydet
            var savedCompanyId = result.id || editingId;
            if (savedCompanyId) {
                var themeIds = Array.from(assignedThemeIds);
                var defaultId = selectedDefaultThemeId || (themeIds.length > 0 ? themeIds[0] : null);
                try {
                    var assignRes = await fetch(API_BASE + '/api/themes/assign', {
                        method: 'POST',
                        headers: { ...authHeaders(), 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            company_id: savedCompanyId,
                            theme_ids: themeIds,
                            default_theme_id: defaultId
                        })
                    });
                    if (!assignRes.ok) {
                        throw new Error('HTTP ' + assignRes.status);
                    }

                    // v2.60.0: Tema değişikliğini anlık yansıt
                    if (window.BrandingEngine && defaultId) {
                        var selectedTheme = themesList.find(function(t) { return t.id === defaultId; });
                        if (selectedTheme) {
                            var bd = BrandingEngine.loadBranding() || {};
                            bd.app_name = data.app_name || bd.app_name;
                            bd.company_id = savedCompanyId;
                            bd.theme = {
                                id: selectedTheme.id,
                                code: selectedTheme.code,
                                css_variables: selectedTheme.css_variables,
                                login_headline: selectedTheme.login_headline || (bd.theme ? bd.theme.login_headline : null),
                                login_subtitle: selectedTheme.login_subtitle || (bd.theme ? bd.theme.login_subtitle : null),
                                features_json: selectedTheme.features_json || (bd.theme ? bd.theme.features_json : null)
                            };
                            BrandingEngine.saveBranding(bd);
                            BrandingEngine.applyAll(bd);
                        }
                    }
                } catch (err) {
                    console.warn('[CompanyModule] Tema atama hatası:', err);
                    if (window.VyraToast) VyraToast.warning('Temalar atanamadı, lütfen tekrar deneyin');
                }
            }

            closeModal();
            await load();

            if (typeof Swal !== 'undefined') {
                Swal.fire({
                    icon: 'success',
                    title: editingId ? 'Firma güncellendi' : 'Firma eklendi',
                    timer: 1500,
                    showConfirmButton: false
                });
            }
        } catch (err) {
            if (typeof Swal !== 'undefined') {
                Swal.fire('Hata', err.message, 'error');
            }
        }
    }

    // --- Delete Handler ---

    async function handleDelete(id) {
        const company = companies.find(c => c.id === id);
        if (!company) return;

        if (typeof Swal !== 'undefined') {
            const result = await Swal.fire({
                title: 'Firmayı Deaktif Et?',
                html: '<strong>' + escapeHtml(company.name) + '</strong> firması deaktif edilecek.',
                icon: 'warning',
                showCancelButton: true,
                confirmButtonText: 'Evet, Deaktif Et',
                cancelButtonText: 'İptal',
                confirmButtonColor: '#ef4444'
            });
            if (!result.isConfirmed) return;
        }

        try {
            await deleteCompany(id);
            await load();
        } catch (err) {
            if (typeof Swal !== 'undefined') {
                Swal.fire('Hata', err.message, 'error');
            }
        }
    }

    // --- Logo Preview ---

    function handleLogoPreview(e) {
        const file = e.target.files[0];
        const preview = document.getElementById('companyLogoPreview');
        if (!file || !preview) return;

        const reader = new FileReader();
        reader.onload = function (ev) {
            preview.innerHTML = '<img src="' + ev.target.result + '" alt="Logo" class="company-logo-preview-img">';
        };
        reader.readAsDataURL(file);
    }

    // --- Load ---

    async function load() {
        await fetchCompanies();
        render();
    }

    // --- Event Delegation ---

    function setupEvents() {
        // Yeni Firma butonu
        const btnNew = document.getElementById('btnNewCompany');
        if (btnNew) {
            btnNew.addEventListener('click', () => openModal(null));
        }

        // Modal kapat
        const btnClose = document.getElementById('btnCloseCompanyModal');
        if (btnClose) btnClose.addEventListener('click', closeModal);

        const btnCancel = document.getElementById('btnCancelCompany');
        if (btnCancel) btnCancel.addEventListener('click', closeModal);

        // ESC ile kapat
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                const modal = document.getElementById('companyModal');
                if (modal && !modal.classList.contains('hidden')) {
                    closeModal();
                }
            }
        });

        // Kaydet
        const btnSave = document.getElementById('btnSaveCompany');
        if (btnSave) btnSave.addEventListener('click', handleSave);


        // Logo dosya seçimi preview
        const logoInput = document.getElementById('companyLogoFile');
        if (logoInput) logoInput.addEventListener('change', handleLogoPreview);

        // İl → İlçe cascade
        const ilSelect = document.getElementById('companyAddressIl');
        if (ilSelect) {
            ilSelect.addEventListener('change', () => {
                loadDistricts(ilSelect.value);
            });
        }

        // İlçe → Mahalle cascade
        const ilceSelect = document.getElementById('companyAddressIlce');
        if (ilceSelect) {
            ilceSelect.addEventListener('change', () => {
                const ilVal = (document.getElementById('companyAddressIl') || {}).value || '';
                loadNeighborhoods(ilVal, ilceSelect.value);
            });
        }

        // Event delegation: düzenle ve sil butonları
        const grid = document.getElementById('companyGrid');
        if (grid) {
            grid.addEventListener('click', (e) => {
                const editBtn = e.target.closest('[data-company-edit]');
                if (editBtn) {
                    const id = parseInt(editBtn.dataset.companyEdit, 10);
                    openModal(id);
                    return;
                }

                const deleteBtn = e.target.closest('[data-company-delete]');
                if (deleteBtn) {
                    const id = parseInt(deleteBtn.dataset.companyDelete, 10);
                    handleDelete(id);
                }
            });
        }
    }

    // --- Init ---

    function init() {
        setupEvents();
    }

    // Public API
    return {
        init: init,
        load: load,
        openModal: openModal
    };
})();

// Otomatik init
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', window.CompanyModule.init);
} else {
    window.CompanyModule.init();
}


